async (params, browser) => {
  // Open page
  await browser.open(`https://www.coinbase.com/price/${params.asset_slug}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="Price"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1')?.textContent?.trim() || ''; const price = document.querySelector('[class*="Price"], [data-testid*="price"]')?.textContent?.trim() || ''; const stats = {}; document.querySelectorAll('dt').forEach(dt => { const dd = dt.nextElementSibling; if (dd) stats[dt.textContent.trim().toLowerCase()] = dd.textContent.trim(); }); const about = document.querySelector('section p, [class*="About"] p, [class*="description"] p')?.textContent?.trim()?.substring(0, 1500) || ''; const links = Array.from(document.querySelectorAll('a[href*="http"][rel]')).slice(0, 5).map(a => ({ text: a.textContent.trim(), url: a.href })); return { asset: '' + params.asset_slug + '', name, price, stats, about, links, url: window.location.href }`)

  return page_data
}
